        <thead>
            <tr>
                <th>Id</th>
                <th>Genre</th>
                <th>statut</th>
                <th>actions</th>
            </tr>
        </thead>
        <tbody>
        {% for genre in genres %}
            <tr>
                <td>{{ genre.id }}</td>
                <td>{{ genre.nomGenre }}</td>
                <td>{{ genre.statut ? \x27Yes\x27 : \x27No\x27 }}</td>
                <td>
                    <a href=\"{{ path(\x27genre_show\x27, {\x27id\x27: genre.id}) }}\"><button class=\"btn btn-outline-dark\">Voir</button></a>
